import java.io.File;
import java.io.FileInputStream;
import java.util.HashMap;
import java.util.Map;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

public class XMLConfigParser {

    public Map<String, String> parseConfigFile(File configFile) throws Exception {
        Map<String, String> configMap = new HashMap<>();

        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        DocumentBuilder db = dbf.newDocumentBuilder();
        Document doc = db.parse(new FileInputStream(configFile));

        NodeList configElements = doc.getElementsByTagName("config");
        Element configElement = (Element) configElements.item(0);

        NodeList settings = configElement.getElementsByTagName("setting");
        for (int i = 0; i < settings.getLength(); i++) {
            Element setting = (Element) settings.item(i);
            String name = setting.getAttribute("name");
            String value = setting.getAttribute("value");
            configMap.put(name, value);
        }

        return configMap;
    }
}